        ArrayList<ArrayList> output = new ArrayList<ArrayList>();

        // Adding subsets without the first element
        output.addAll(rest_subsets);

        // Adding subsets with the first element
        for (ArrayList subset : rest_subsets) {
            ArrayList new_subset = new ArrayList(subset);
            new_subset.add(0, first);
            output.add(new_subset);
        }

        return output;
    } else {
        ArrayList<ArrayList> empty_set = new ArrayList<ArrayList>();
        empty_set.add(new ArrayList());
        return empty_set;
    }
}
